mapper.select:
SELECT FROM bs_energy_catalog WHERE deleted = 0
AND name LIKE CONCAT('%', #{name}, '%')
AND category = #{category}
AND is_active = #{isActive}
ORDER BY sort_order, category, id

mapper.update:
UPDATE bs_energy_catalog
SET deleted = 1, update_by = #{updateBy}, update_time = NOW()
WHERE id = #{id}
